import { PublicActionPage } from '@domain/publicActionPage';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import { useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { FormInputControl } from 'src/builder/PublicActionPage/components/FormInputControl';
import { FormSelectControl } from 'src/builder/PublicActionPage/components/SelectControl';

type Props = {
  actionPage?: PublicActionPage;
  isPreview?: boolean;
};

const TITLE_OPTIONS = ['Mr.', 'Mrs.', 'Ms.', 'Miss', 'Dr.', 'Rev.', 'Hon.'];

export const NameField = ({ actionPage, isPreview = false }: Props) => {
  const { trigger, watch } = useFormContext();
  const donorProfile = isPreview ? null : watch('donorProfile');
  const title = watch('title');
  const isDonation = isDonationPage(actionPage?.pageType);

  const {
    displayName = true,
    includeMiddleName = false,
    includeSuffix = false,
    includeTitle = false,
    requireName = false,
    requireTitle = false,
  } = actionPage?.fieldConfiguration || {};

  // leave this shims in so that when we split first / last name requirements
  // it is easier
  const includeFirstName = displayName;
  const includeLastName = displayName;
  const requireFirstAndLastName = requireName;

  const titles = useMemo(() => {
    return [
      {
        label: '-',
        value: '',
      },
      ...TITLE_OPTIONS.map((option) => ({
        label: option,
        value: option,
      })),
    ];
  }, []);

  useEffect(() => {
    if (title) {
      trigger('title');
    }
  }, [title, trigger]);

  return (
    <>
      {(includeFirstName || includeLastName) &&
      (!donorProfile?.firstName || !donorProfile?.lastName) ? (
        <div className="flex w-full gap-2">
          {includeFirstName && (!donorProfile || !donorProfile.firstName) ? (
            <div className="flex grow">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                isRequired={isDonation || requireFirstAndLastName}
                label="First name"
                name="firstName"
              />
            </div>
          ) : null}
          {includeLastName && (!donorProfile || !donorProfile.lastName) ? (
            <div className="flex grow">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                isRequired={isDonation || requireFirstAndLastName}
                label="Last name"
                name="lastName"
              />
            </div>
          ) : null}
        </div>
      ) : null}
      {(includeMiddleName || includeSuffix || includeTitle || requireTitle) && (
        <div className="mt-2 flex items-stretch gap-2">
          {includeMiddleName && (
            <div className="flex w-full">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                label="Middle name"
                name="middleName"
              />
            </div>
          )}
          {includeTitle && (
            <div className="w-[106px] min-w-[106px] max-w-[106px]">
              <FormSelectControl
                className="w-[106px] min-w-[106px] max-w-[106px]"
                formControlProps={{ className: 'mb-0' }}
                isRequired={requireTitle}
                label="Title"
                name="title"
                options={titles}
              />
            </div>
          )}
          {includeSuffix && (
            <div className="w-[106px] min-w-[106px] max-w-[106px]">
              <FormInputControl
                formControlProps={{ className: 'mb-0' }}
                label="Suffix"
                name="suffix"
              />
            </div>
          )}
        </div>
      )}
    </>
  );
};
